        // Добавляем parent_id для некоторых ответов
        $createdComments = [];
        foreach ($comments as $i => $commentData) {
            $createdComments[] = Comment::create($commentData);
        }

        // Делаем комментарии 2, 5, 6 ответами на комментарии 0, 3, 4
        $createdComments[2]->update(['parent_id' => $createdComments[1]->id]);
        $createdComments[7]->update(['parent_id' => $createdComments[6]->id]);
        $createdComments[12]->update(['parent_id' => $createdComments[11]->id]);

        // Голоса
        foreach ($createdArticles as $article) {
            $voterCount = rand(2, 4);
            $voters = $allUsers->random($voterCount);
            foreach ($voters as $voter) {
                $type = rand(0, 4) > 0 ? 'up' : 'down'; // 80% up, 20% down
                Vote::create([
                    'user_id'    => $voter->id,
                    'article_id' => $article->id,
                    'type'       => $type,
                ]);
            }

            $upVotes   = $article->votes()->where('type', 'up')->count();
            $downVotes = $article->votes()->where('type', 'down')->count();
            $article->update(['votes_count' => $upVotes - $downVotes]);
        }
